export const HourglassAnimation: React.FC<any> = (props) => {
  const { position = { x: 0.35, y: 0.15, w: 0.3, h: 0.7 } } = props;
  const frame = useCurrentFrame();
  const { fps, durationInFrames, width, height } = useVideoConfig();

  // === Configuration ===
  const GLASS_STROKE = "#94A3B8";
  const GLASS_FILL = "rgba(15,23,42,0.06)";
  const SAND_TOP = "#F59E0B";
  const SAND_MID = "#D97706";
  const SAND_BOTTOM = "#92400E";
  const SAND_STREAM = "#FBBF24";
  const CAP_COLOR = "#475569";
  const CAP_HIGHLIGHT = "#94A3B8";
  const CAP_EDGE = "#334155";
  const FRAME_COLOR = "#64748B";

  // === Fade out ===
  const fadeOutStart = durationInFrames - Math.round(fps * 0.5);
  const exitOpacity = interpolate(
    frame,
    [fadeOutStart, durationInFrames],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  // === Entrance ===
  const entrance = spring({
    frame,
    fps,
    config: { damping: 20, mass: 0.5, stiffness: 200 },
  });
  const entranceScale = interpolate(entrance, [0, 1], [0.5, 1]);
  const entranceOpacity = interpolate(entrance, [0, 1], [0, 1]);

  // === Sand cycle ===
  const cycleDuration = Math.max(fps * 4, 120);
  const flipDuration = Math.round(fps * 0.6);
  const cycleFrame = frame % cycleDuration;
  const cycleIndex = Math.floor(frame / cycleDuration);

  const isFlipping = cycleFrame < flipDuration;
  const sandPhaseFrame = isFlipping ? 0 : cycleFrame - flipDuration;
  const sandPhaseDuration = cycleDuration - flipDuration;

  // Eased sand progress — starts fast, slows down (like real sand)
  const rawSandProgress = interpolate(
    sandPhaseFrame,
    [0, sandPhaseDuration],
    [0, 1],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );
  // Apply easing curve for realistic flow
  const sandProgress = rawSandProgress < 0.5
    ? 2 * rawSandProgress * rawSandProgress
    : 1 - Math.pow(-2 * rawSandProgress + 2, 2) / 2;

  // Flip rotation with stronger spring
  const flipSpring = isFlipping
    ? spring({
        frame: cycleFrame,
        fps,
        config: { damping: 12, mass: 1.0, stiffness: 60 },
      })
    : 1;
  const targetRotation = cycleIndex * 180;
  const flipRotation = isFlipping
    ? interpolate(flipSpring, [0, 1], [targetRotation - 180, targetRotation])
    : targetRotation;

  // Subtle sway during flip
  const flipSway = isFlipping
    ? Math.sin(flipSpring * Math.PI) * 3
    : 0;

  // === Positioning ===
  const left = position.x * width;
  const top = position.y * height;
  const maxWidth = position.w * width;
  const maxHeight = position.h * height;

  const svgW = maxWidth;
  const svgH = maxHeight;
  const cx = svgW / 2;
  const cy = svgH / 2;

  // Hourglass proportions
  const bulbW = svgW * 0.26;
  const bulbH = svgH * 0.35;
  const neckR = svgW * 0.022;
  const capW = svgW * 0.38;
  const capH = svgH * 0.03;
  const capR = capH * 0.35;
  const strutW = svgW * 0.008;

  // Sand heights
  const topSandMax = bulbH * 0.72;
  const bottomSandMax = bulbH * 0.72;
  const topSandH = topSandMax * (1 - sandProgress);
  const bottomSandH = bottomSandMax * sandProgress;

  // Stream properties
  const streamActive = sandProgress > 0.01 && sandProgress < 0.97 && !isFlipping;
  const streamWobble = Math.sin(frame * 1.2) * 0.15 + 0.85;
  const streamThickness = neckR * 0.5 * streamWobble *
    interpolate(sandProgress, [0, 0.05, 0.9, 0.97], [0, 1, 1, 0], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

  // Particles
  const particles = useMemo(() => {
    return Array.from({ length: 18 }, (_, i) => ({
      offsetX: (Math.random() - 0.5) * neckR * 4,
      speed: 0.5 + Math.random() * 1.0,
      size: 0.5 + Math.random() * 1.8,
      phase: Math.random() * Math.PI * 2,
      delay: Math.random() * 20,
    }));
  }, [neckR]);

  // Hourglass profile — more elegant curved shape
  const topBulbPath = `
    M ${cx - bulbW * 0.05} ${cy - bulbH}
    L ${cx - bulbW} ${cy - bulbH}
    C ${cx - bulbW} ${cy - bulbH * 0.35} ${cx - neckR * 1.8} ${cy - neckR * 0.5} ${cx - neckR} ${cy}
    L ${cx + neckR} ${cy}
    C ${cx + neckR * 1.8} ${cy - neckR * 0.5} ${cx + bulbW} ${cy - bulbH * 0.35} ${cx + bulbW} ${cy - bulbH}
    L ${cx + bulbW * 0.05} ${cy - bulbH}
    Z
  `;

  const bottomBulbPath = `
    M ${cx - neckR} ${cy}
    C ${cx - neckR * 1.8} ${cy + neckR * 0.5} ${cx - bulbW} ${cy + bulbH * 0.35} ${cx - bulbW} ${cy + bulbH}
    L ${cx + bulbW} ${cy + bulbH}
    C ${cx + bulbW} ${cy + bulbH * 0.35} ${cx + neckR * 1.8} ${cy + neckR * 0.5} ${cx + neckR} ${cy}
    Z
  `;

  // Top sand shape (follows bulb curvature)
  const getTopSandWidth = (h: number) => {
    const ratio = h / bulbH;
    return bulbW * (0.15 + ratio * 0.85);
  };

  const topSandWidth = getTopSandWidth(topSandH);
  const bottomSandWidth = getTopSandWidth(bottomSandH);

  // Unique IDs for this instance
  const uid = useMemo(() => `hg-${Math.random().toString(36).slice(2, 8)}`, []);

  return (
    <div
      style={{
        position: "absolute",
        left,
        top,
        maxWidth,
        maxHeight,
        overflow: "hidden",
        opacity: exitOpacity * entranceOpacity,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          transform: `scale(${entranceScale}) rotate(${flipRotation}deg) translateX(${flipSway}px)`,
          transformOrigin: "center center",
          willChange: "transform",
        }}
      >
        <svg
          width={svgW}
          height={svgH}
          viewBox={`0 0 ${svgW} ${svgH}`}
        >
          <defs>
            <linearGradient id={`${uid}-sand-top`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={SAND_TOP} />
              <stop offset="60%" stopColor={SAND_MID} />
              <stop offset="100%" stopColor={SAND_BOTTOM} />
            </linearGradient>
            <linearGradient id={`${uid}-sand-bot`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={SAND_MID} />
              <stop offset="100%" stopColor={SAND_BOTTOM} />
            </linearGradient>
            <linearGradient id={`${uid}-cap`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={CAP_HIGHLIGHT} />
              <stop offset="50%" stopColor={CAP_COLOR} />
              <stop offset="100%" stopColor={CAP_EDGE} />
            </linearGradient>
            <linearGradient id={`${uid}-glass`} x1="0" y1="0" x2="1" y2="1">
              <stop offset="0%" stopColor="rgba(255,255,255,0.1)" />
              <stop offset="50%" stopColor="rgba(255,255,255,0.02)" />
              <stop offset="100%" stopColor="rgba(255,255,255,0.06)" />
            </linearGradient>
            <radialGradient id={`${uid}-sand-glow`} cx="50%" cy="30%" r="60%">
              <stop offset="0%" stopColor={SAND_TOP} stopOpacity={0.3} />
              <stop offset="100%" stopColor={SAND_TOP} stopOpacity={0} />
            </radialGradient>
            <clipPath id={`${uid}-top-clip`}>
              <path d={topBulbPath} />
            </clipPath>
            <clipPath id={`${uid}-bot-clip`}>
              <path d={bottomBulbPath} />
            </clipPath>
            <filter id={`${uid}-blur`}>
              <feGaussianBlur stdDeviation={svgW * 0.005} />
            </filter>
          </defs>

          {/* Support struts */}
          <rect
            x={cx - capW / 2 + strutW}
            y={cy - bulbH - capH * 0.5}
            width={strutW}
            height={bulbH * 2 + capH}
            fill={FRAME_COLOR}
            opacity={0.4}
            rx={strutW / 2}
          />
          <rect
            x={cx + capW / 2 - strutW * 2}
            y={cy - bulbH - capH * 0.5}
            width={strutW}
            height={bulbH * 2 + capH}
            fill={FRAME_COLOR}
            opacity={0.4}
            rx={strutW / 2}
          />

          {/* Top cap — layered for depth */}
          <rect
            x={cx - capW / 2}
            y={cy - bulbH - capH * 1.3}
            width={capW}
            height={capH * 1.3}
            rx={capR}
            fill={`url(#${uid}-cap)`}
            stroke={CAP_EDGE}
            strokeWidth={0.8}
          />
          <rect
            x={cx - capW / 2 + 2}
            y={cy - bulbH - capH * 1.3 + 1}
            width={capW - 4}
            height={capH * 0.35}
            rx={capR * 0.5}
            fill="rgba(255,255,255,0.12)"
          />

          {/* Bottom cap */}
          <rect
            x={cx - capW / 2}
            y={cy + bulbH}
            width={capW}
            height={capH * 1.3}
            rx={capR}
            fill={`url(#${uid}-cap)`}
            stroke={CAP_EDGE}
            strokeWidth={0.8}
          />
          <rect
            x={cx - capW / 2 + 2}
            y={cy + bulbH + 1}
            width={capW - 4}
            height={capH * 0.35}
            rx={capR * 0.5}
            fill="rgba(255,255,255,0.12)"
          />

          {/* Top bulb glass */}
          <path
            d={topBulbPath}
            fill={GLASS_FILL}
            stroke={GLASS_STROKE}
            strokeWidth={1.4}
            strokeOpacity={0.3}
          />

          {/* Bottom bulb glass */}
          <path
            d={bottomBulbPath}
            fill={GLASS_FILL}
            stroke={GLASS_STROKE}
            strokeWidth={1.4}
            strokeOpacity={0.3}
          />

          {/* Top sand body */}
          {topSandH > 0.5 && (
            <g clipPath={`url(#${uid}-top-clip)`}>
              <rect
                x={cx - bulbW * 1.1}
                y={cy - topSandH}
                width={bulbW * 2.2}
                height={topSandH + 1}
                fill={`url(#${uid}-sand-top)`}
              />
              {/* Sand surface highlight */}
              <ellipse
                cx={cx}
                cy={cy - topSandH + 0.5}
                rx={topSandWidth * 0.75}
                ry={svgH * 0.006}
                fill={SAND_TOP}
                opacity={0.5}
              />
              {/* Funnel depression at center */}
              {streamActive && topSandH > 3 && (
                <>
                  <ellipse
                    cx={cx}
                    cy={cy - topSandH + 1.5}
                    rx={neckR * 2.5 * Math.min(1, sandProgress * 8)}
                    ry={svgH * 0.008 * Math.min(1, sandProgress * 4)}
                    fill={SAND_BOTTOM}
                    opacity={0.5}
                  />
                  {/* Tiny crater lines */}
                  <line
                    x1={cx - neckR * 1.5}
                    y1={cy - topSandH + 2}
                    x2={cx}
                    y2={cy - topSandH + 3}
                    stroke={SAND_BOTTOM}
                    strokeWidth={0.4}
                    opacity={0.4 * Math.min(1, sandProgress * 6)}
                  />
                  <line
                    x1={cx + neckR * 1.5}
                    y1={cy - topSandH + 2}
                    x2={cx}
                    y2={cy - topSandH + 3}
                    stroke={SAND_BOTTOM}
                    strokeWidth={0.4}
                    opacity={0.4 * Math.min(1, sandProgress * 6)}
                  />
                </>
              )}
            </g>
          )}

          {/* Bottom sand body */}
          {bottomSandH > 0.5 && (
            <g clipPath={`url(#${uid}-bot-clip)`}>
              <rect
                x={cx - bulbW * 1.1}
                y={cy + bulbH - bottomSandH}
                width={bulbW * 2.2}
                height={bottomSandH + 1}
                fill={`url(#${uid}-sand-bot)`}
              />
              {/* Mound on top of bottom sand */}
              <ellipse
                cx={cx}
                cy={cy + bulbH - bottomSandH}
                rx={neckR * 2.5 * Math.min(1, sandProgress * 4)}
                ry={svgH * 0.018 * Math.min(1, sandProgress * 3)}
                fill={SAND_MID}
                opacity={0.6}
              />
              {/* Surface detail */}
              <ellipse
                cx={cx}
                cy={cy + bulbH - bottomSandH + 0.5}
                rx={bottomSandWidth * 0.6}
                ry={svgH * 0.004}
                fill={SAND_TOP}
                opacity={0.3}
              />
            </g>
          )}

          {/* Falling sand stream */}
          {streamActive && (
            <g>
              {/* Main stream */}
              <line
                x1={cx}
                y1={cy - neckR * 0.5}
                x2={cx}
                y2={cy + bulbH - bottomSandH}
                stroke={SAND_STREAM}
                strokeWidth={streamThickness}
                opacity={0.9}
                strokeLinecap="round"
              />
              {/* Secondary thinner stream */}
              <line
                x1={cx}
                y1={cy}
                x2={cx + Math.sin(frame * 0.3) * neckR * 0.3}
                y2={cy + (bulbH - bottomSandH) * 0.6}
                stroke={SAND_TOP}
                strokeWidth={streamThickness * 0.4}
                opacity={0.5}
                strokeLinecap="round"
              />
              {/* Splash particles at landing */}
              {particles.slice(0, 6).map((p, i) => {
                const splashFrame = (frame + p.delay) % 15;
                const splashActive = splashFrame < 8 && sandProgress > 0.05;
                if (!splashActive) return null;
                const splashY = cy + bulbH - bottomSandH;
                const splashX = cx + Math.sin(p.phase + frame * 0.2) * neckR * 3;
                const splashOp = interpolate(splashFrame, [0, 8], [0.6, 0], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
                const splashDy = interpolate(splashFrame, [0, 8], [0, -svgH * 0.015], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
                return (
                  <circle
                    key={`splash-${i}`}
                    cx={splashX}
                    cy={splashY + splashDy}
                    r={p.size * 0.5}
                    fill={SAND_TOP}
                    opacity={splashOp}
                  />
                );
              })}
              {/* Falling particles in stream */}
              {particles.map((p, i) => {
                const fallRange = bulbH - bottomSandH;
                if (fallRange < 2) return null;
                const particleY = cy + ((frame * p.speed * 4 + p.phase * 40) % fallRange);
                const wobbleX = Math.sin(frame * 0.2 + p.phase) * p.offsetX * 0.5;
                const particleOpacity = interpolate(
                  particleY,
                  [cy, cy + fallRange],
                  [0.7, 0.15],
                  { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
                );
                return (
                  <circle
                    key={`fall-${i}`}
                    cx={cx + wobbleX}
                    cy={particleY}
                    r={p.size * 0.45}
                    fill={SAND_TOP}
                    opacity={particleOpacity * 0.5}
                  />
                );
              })}
            </g>
          )}

          {/* Glass reflections */}
          <path
            d={`M ${cx - bulbW * 0.65} ${cy - bulbH * 0.9}
                C ${cx - bulbW * 0.72} ${cy - bulbH * 0.5} ${cx - bulbW * 0.4} ${cy - bulbH * 0.2} ${cx - neckR * 2.5} ${cy - neckR * 2}`}
            fill="none"
            stroke="rgba(255,255,255,0.18)"
            strokeWidth={1.8}
            strokeLinecap="round"
          />
          <path
            d={`M ${cx - bulbW * 0.5} ${cy + bulbH * 0.2}
                C ${cx - bulbW * 0.55} ${cy + bulbH * 0.5} ${cx - bulbW * 0.65} ${cy + bulbH * 0.7} ${cx - bulbW * 0.5} ${cy + bulbH * 0.92}`}
            fill="none"
            stroke="rgba(255,255,255,0.1)"
            strokeWidth={1.2}
            strokeLinecap="round"
          />

          {/* Specular highlights */}
          <circle
            cx={cx - bulbW * 0.5}
            cy={cy - bulbH * 0.78}
            r={svgW * 0.01}
            fill="rgba(255,255,255,0.35)"
          />
          <circle
            cx={cx - bulbW * 0.4}
            cy={cy - bulbH * 0.65}
            r={svgW * 0.005}
            fill="rgba(255,255,255,0.2)"
          />

          {/* Glass overlay for depth */}
          <path d={topBulbPath} fill={`url(#${uid}-glass)`} />
          <path d={bottomBulbPath} fill={`url(#${uid}-glass)`} />
        </svg>
      </div>
    </div>
  );
};

